INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 1, 'PALABRA de Jehová que fué á Joel hijo de Pethuel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 2, 'Oid esto, viejos, y escuchad, todos los moradores de la tierra. ¿Ha acontecido esto en vuestros días, ó en los días de vuestros padres?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 3, 'De esto contaréis á vuestros hijos, y vuestros hijos á sus hijos, y su hijos á la otra generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 4, 'Lo que quedó de la oruga comió la langosta, y lo que quedó de la langosta comió el pulgón; y el revoltón comió lo que del pulgón había quedado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 5, 'Despertad, borrachos, y llorad; aullad todos los que bebéis vino, á causa del mosto, porque os es quitado de vuestra boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 6, 'Porque gente subió á mi tierra, fuerte y sin número; sus dientes, dientes de león, y sus muelas, de león.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 7, 'Asoló mi vid, y descortezó mi higuera: del todo la desnudó y derribó: sus ramas quedaron blancas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 8, 'Llora tú como moza vestida de saco por el marido de su juventud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 9, 'Pereció el presente y la libación de la casa de Jehová: los sacerdotes ministros de Jehová hicieron luto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 10, 'El campo fué destruído, enlutóse la tierra; porque el trigo fué destuído, se secó el mosto, perdióse el aceite.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 11, 'Confundíos, labradores, aullad, viñeros, por el trigo y la cebada; porque se perdió la mies del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 12, 'Secóse la vid, y pereció la higuera, el granado también, la palma, y el manzano; secáronse todos los árboles del campo; por lo cual se secó el gozo de los hijos de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 13, 'Ceñíos y lamentad, sacerdotes; aullad, ministros del altar; venid, dormid en sacos, ministros de mi Dios: porque quitado es de la casa de vuestro Dios el presente y la libación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 14, 'Pregonad ayuno, llamad á congregación; congregad los ancianos y todos los moradores de la tierra en la casa de Jehová vuestro Dios, y clamad á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 15, '¡Ay del día! porque cercano está el día de Jehová, y vendrá como destrucción por el Todopoderoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 16, '¿No es quitado el mantenimiento de delante de nuestros ojos, la alegría y el placer de la casa de nuestro Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 17, 'El grano se pudrió debajo de sus terrones, los bastimentos fueron asolados, los alfolíes destruídos; porque se secó el trigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 18, '¡Cuánto gimieron las bestias! ¡cuán turbados anduvieron los hatos de los bueyes, porque no tuvieron pastos! también fueron asolados los rebaños de las ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 19, 'A ti, oh Jehová, clamaré: porque fuego consumió los pastos del desierto, y llama abrasó todos los árboles del campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 1, 20, 'Las bestias del campo bramarán también á ti; porque se secaron los arroyos de las aguas, y fuego consumió las praderías del desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 1, 'TOCAD trompeta en Sión, y pregondad en mi santo monte: tiemblen todos los moradores de la tierra; porque viene el día de Jehová, porque está cercano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 2, 'Día de tinieblas y de oscuridad, día de nube y de sombra, que sobre los montes se derrama como el alba: un pueblo grande y fuerte: nunca desde el siglo fué semejante, ni después de él será jamás en años de generación en generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 3, 'Delante de él consumirá fuego, tras de él abrasará llama; como el huerto de Edén será la tierra delante de él, y detrás de él como desierto asolado; ni tampoco habrá quien de él escape.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 4, 'Su parecer, como parecer de caballos; y como gente de á caballo correrán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 5, 'Como estruendo de carros saltarán sobre las cumbres de los montes; como sonido de llama de fuego que consume hojarascas, como fuerte pueblo aparejado para la batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 6, 'Delante de él temerán los pueblos, pondránse mustios todos los semblantes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 7, 'Como valientes correrán, como hombres de guerra subirán la muralla; y cada cual irá en sus caminos, y no torcerán sus sendas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 8, 'Ninguno apretará á su compañero, cada uno irá por su carrera; y aun cayendo sobre la espada no se herirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 9, 'Irán por la ciudad, correrán por el muro, subirán por las casas, entrarán por las ventanas á manera de ladrones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 10, 'Delante de él temblará la tierra, se estremecerán los cielos: el sol y la luna se oscurecerán, y las estrellas retraerán su resplandor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 11, 'Y Jehová dará su voz delante de su ejército: porque muchos son sus reales y fuertes, que ponen en efecto su palabra: porque grande es el día de Jehová, y muy terrible; ¿y quién lo podrá sufrir?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 12, 'Por eso pues ahora, dice Jehová, convertíos á mí con todo vuestro corazón, con ayuno y lloro y llanto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 13, 'Y lacerad vuestro corazón, y no vuestros vestidos; y convertíos á Jehová vuestro Dios; porque misericordioso es y clemente, tardo para la ira, y grande en misericordia, y que se arrepiente del castigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 14, '¿Quién sabe si volverá, y se apiadará, y dejará bendición tras de él, presente y libación para Jehová Dios vuestro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 15, 'Tocad trompeta en Sión, pregonad ayuno, llamad á congregación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 16, 'Reunid el pueblo, santificad la reunión, juntad los viejos, congregad los niños y los que maman: salga de su cámara el novio, y de su tálamo la novia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 17, 'Entre la entrada y el altar, lloren los sacerdotes, ministros de Jehová, y digan: Perdona, oh Jehová, á tu pueblo, y no pongas en oprobio tu heredad, para que las gentes se enseñoreen de ella. ¿Por qué han de decir entre los pueblos: Dónde está su Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 18, 'Y Jehová celará su tierra, y perdonará su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 19, 'Y responderá Jehová, y dirá á su pueblo: He aquí yo os envío pan, y mosto, y aceite, y seréis saciados de ellos: y nunca más os pondré en oprobio entre las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 20, 'Y haré alejar de vosotros al del aquilón, y echarélo en la tierra seca y desierta: su faz será hacia el mar oriental, y su fin al mar occidental, y exhalará su hedor; y subirá su pudrición, porque hizo grandes cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 21, 'Tierra, no temas; alégrate y gózate: porque Jehová ha de hacer grandes cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 22, 'Animales del campo, no temáis; porque los pastos del desierto reverdecerán, porque los árboles llevarán su fruto, la higuera y la vid darán sus frutos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 23, 'Vosotros también, hijos de Sión, alegraos y gozaos en Jehová vuestro Dios; porque os ha dado la primera lluvia arregladamente, y hará descender sobre vosotros lluvia temprana y tardía como al principio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 24, 'Y las eras se henchirán de trigo, y los lagares rebosarán de vino y aceite.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 25, 'Y os restituiré los años que comió la oruga, la langosta, el pulgón, y el revoltón; mi grande ejército que envié contra vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 26, 'Y comeréis hasta saciaros, y alabaréis el nombre de Jehová vuestro Dios, el cual hizo maravillas con vosotros: y nunca jamás será mi pueblo avergonzado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 27, 'Y conoceréis que en medio de Israel estoy yo, y que yo soy Jehová vuestro Dios, y no hay otro: y mi pueblo nunca jamás será avergonzado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 28, 'Y será que después de esto, derramaré mi Espíritu sobre toda carne, y profetizarán vuestros hijos y vuestras hijas; vuestros viejos soñarán sueños, y vuestros mancebos verán visiones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 29, 'Y aun también sobre los siervos y sobre las siervas derramaré mi Espíritu en aquellos días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 30, 'Y daré prodigios en el cielo y en la tierra, sangre, y fuego, y columnas de humo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 31, 'El sol se tornará en tinieblas, y la luna en sangre, antes que venga el día grande y espantoso de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 2, 32, 'Y será que cualquiera que invocare el nombre de Jehová, será salvo: porque en el monte de Sión y en Jerusalem habrá salvación, como Jehová ha dicho, y en los que quedaren, á los cuales Jehová habrá llamado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 1, 'PORQUE he aquí que en aquellos días, y en aquel tiempo en que haré tornar la cautividad de Judá y de Jerusalem,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 2, 'Juntaré todas las gentes, y harélas descender al valle de Josaphat, y allí entraré en juicio con ellos á causa de mi pueblo, y de Israel mi heredad, á los cuales esparcieron entre las naciones, y partieron mi tierra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 3, 'Y echaron suertes sobre mi pueblo, y á los niños dieron por una ramera, y vendieron las niñas por vino para beber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 4, 'Y también, ¿qué tengo yo con vosotras, Tiro y Sidón, y todos los términos de Palestina? ¿Queréis vengaros de mí? Y si de mí os vengáis, bien pronto haré yo recaer la paga sobre vuestra cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 5, 'Porque habéis llevado mi plata y mi oro, y mis cosas preciosas y hermosas metisteis en vuestros templos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 6, 'Y vendisteis los hijos de Judá y los hijos de Jerusalem á los hijos de los Griegos, por alejarlos de sus términos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 7, 'He aquí los levantaré yo del lugar donde los vendisteis, y volveré vuestra paga sobre vuestra cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 8, 'Y venderé vuestros hijos y vuestras hijas en la mano de los hijos de Judá, y ellos los venderán á los Sabeos, nación apartada; porque Jehová ha hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 9, 'Pregonad esto entre las gentes, proclamad guerra, despertad á los valientes, lléguense, vengan todos los hombres de guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 10, 'Haced espadas de vuestros azadones, lanzas de vuestras hoces; diga el flaco: Fuerte soy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 11, 'Juntaos y venid, gentes todas de alrededor, y congregaos: haz venir allí, oh Jehová, tus fuertes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 12, 'Las gentes se despierten, y suban al valle de Josaphat: porque allí me sentaré para juzgar todas las gentes de alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 13, 'Echad la hoz, porque la mies está ya madura. Venid, descended; porque el lagar está lleno, rebosan las lagaretas: porque mucha es la maldad de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 14, 'Muchos pueblos en el valle de la decisión: porque cercano está el día de Jehová en el valle de la decisión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 15, 'El sol y la luna se oscurecerán, y las estrellas retraerán su resplandor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 16, 'Y Jehová bramará desde Sión, y dará su voz desde Jerusalem, y temblarán los cielos y la tierra: mas Jehová será la esperanza de su pueblo, y la fortaleza de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 17, 'Y conoceréis que yo soy Jehová vuestro Dios, que habito en Sión, monte de mi santidad: y será Jerusalem santa, y extraños no pasarán más por ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 18, 'Y será en aquel tiempo, que los montes destilarán mosto, y los collados fluirán leche, y por todos los arroyos de Judá correrán aguas: y saldrá una fuente de la casa de Jehová, y regará el valle de Sittim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 19, 'Egipto será destruído, y Edom será vuelto en asolado desierto, por la injuria hecha á los hijos de Judá: porque derramaron en su tierra la sangre inocente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 20, 'Mas Judá para siempre será habitada, y Jerusalem en generación y generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JOL', 'Joel', 3, 21, 'Y limpiaré la sangre de los que no limpié; y Jehová morará en Sión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 1, 1, 'LAS palabras de Amós, que fué entre los pastores de Tecoa, las cuales vió acerca de Israel en días de Uzzía rey de Judá, y en días de Jeroboam hijo de Joas rey de Israel, dos años antes del terremoto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 1, 2, 'Y dijo: Jehová bramará desde Sión, y dará su voz desde Jerusalem; y las estancias de los pastores se enlutarán, y secaráse la cumbre del Carmelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 1, 3, 'Así ha dicho Jehová: Por tres pecados de Damasco, y por el cuarto, no desviaré su castigo; porque trillaron á Galaad con trillos de hierro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 1, 4, 'Y meteré fuego en la casa de Hazael, y consumirá los palacios de Ben-hadad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 1, 5, 'Y quebraré la barra de Damasco, y talaré los moradores de Bicath-aven, y los gobernadores de Beth-eden: y el pueblo de Aram será trasportado á Chîr, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 1, 6, 'Así ha dicho Jehová: Por tres pecados de Gaza, y por el cuarto, no desviaré su castigo; porque llevó cautiva toda la cautividad, para entregarlos á Edom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 1, 7, 'Y meteré fuego en el muro de Gaza, y quemará sus palacios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 1, 8, 'Y talaré los moradores de Azoto, y los gobernadores de Ascalón: y tornaré mi mano sobre Ecrón, y las reliquias de los Palestinos perecerán, ha dicho el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 1, 9, 'Así ha dicho Jehová: Por tres pecados de Tiro, y por el cuarto, no desviaré su castigo; porque entregaron la cautividad entera á Edom, y no se acordaron del concierto de hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 1, 10, 'Y meteré fuego en el muro de Tiro, y consumirá sus palacios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 1, 11, 'Así ha dicho Jehová: Por tres pecados de Edom, y por el cuarto, no desviaré su castigo; porque persiguió á cuchillo á su hermano, y rompió sus conmiseraciones; y con su furor le ha robado siempre, y ha perpetuamente guardado el enojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 1, 12, 'Y meteré fuego en Temán, y consumirá los palacios de Bosra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 1, 13, 'Así ha dicho Jehová: Por tres pecados de los hijos de Ammón, y por el cuarto, no desviaré su castigo; porque abrieron las preñadas de Galaad, para ensanchar su término.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 1, 14, 'Y encenderé fuego en el muro de Rabba, y consumirá sus palacios con estruendo en día de batalla, con tempestad en día tempestuoso:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 1, 15, 'Y su rey irá en cautiverio, él y sus príncipes todos, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 2, 1, 'ASI ha dicho Jehová: Por tres pecados de Moab, y por el cuarto, no desviaré su castigo; porque quemó los huesos del rey de Idumea hasta tornarlos en cal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 2, 2, 'Y meteré fuego en Moab, y consumirá los palacios de Chêrioth: y morirá Moab en alboroto, en estrépito y sonido de trompeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 2, 3, 'Y quitaré el juez de en medio de él, y mataré con él á todos sus príncipes, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 2, 4, 'Así ha dicho Jehová: Por tres pecados de Judá, y por el cuarto, no desviaré su castigo; porque menospreciaron la ley de Jehová, y no guardaron sus ordenanzas; é hiciéronlos errar sus mentiras, en pos de las cuales anduvieron sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 2, 5, 'Meteré por tanto fuego en Judá, el cual consumirá los palacios de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 2, 6, 'Así ha dicho Jehová: Por tres pecados de Israel, y por el cuarto, no desviaré su castigo; porque vendieron por dinero al justo, y al pobre por un par de zapatos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 2, 7, 'Que anhelan porque haya polvo de tierra sobre la cabeza de los pobres, y tuercen el camino de los humildes: y el hombre y su padre entraron á la misma moza, profanando mi santo nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 2, 8, 'Y sobre las ropas empeñadas se acuestan junto á cualquier altar; y el vino de los penados beben en la casa de sus dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 2, 9, 'Y yo destruí delante de ellos al Amorrheo, cuya altura era como la altura de los cedros, y fuerte como un alcornoque; y destruí su fruto arriba, sus raíces abajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 2, 10, 'Y yo os hice á vosotros subir de la tierra de Egipto, y os traje por el desierto cuarenta años, para que poseyeseis la tierra del Amorrheo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 2, 11, 'Y levanté de vuestros hijos para profetas, y de vuestros mancebos para que fuesen Nazareos. ¿No es esto así, dice Jehová, hijos de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 2, 12, 'Mas vosotros disteis de beber vino á los Nazareos; y á los profetas mandasteis, diciendo: No profeticéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 2, 13, 'Pues he aquí, yo os apretaré en vuestro lugar, como se aprieta el carro lleno de haces;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 2, 14, 'Y la huída perecerá del ligero, y el fuerte no esforzará su fuerza, ni el valiente librará su vida;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 2, 15, 'Y el que toma el arco no resistirá, ni escapará el ligero de pies, ni el que cabalga en caballo salvará su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 2, 16, 'El esforzado entre esforzados huirá desnudo aquel día, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 3, 1, 'OID esta palabra que ha hablado Jehová contra vosotros, hijos de Israel, contra toda la familia que hice subir de la tierra de Egipto. Dice así:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 3, 2, 'A vosotros solamente he conocido de todas las familias de la tierra; por tanto visitaré contra vosotros todas vuestras maldades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 3, 3, '¿Andarán dos juntos, si no estuvieren de concierto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 3, 4, '¿Bramará el león en el monte sin hacer presa? ¿dará el leoncillo su bramido desde su morada, si no prendiere?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 3, 5, '¿Caerá el ave en el lazo en la tierra, sin haber armador? ¿alzaráse el lazo de la tierra, si no se ha prendido algo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 3, 6, '¿Tocaráse la trompeta en la ciudad, y no se alborotará el pueblo? ¿habrá algún mal en la ciudad, el cual Jehová no haya hecho?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 3, 7, 'Porque no hará nada el Señor Jehová, sin que revele su secreto á sus siervos los profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 3, 8, 'Bramando el león, ¿quién no temerá? hablando el Señor Jehová, ¿quién no porfetizará?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 3, 9, 'Haced pregonar sobre los palacios de Azoto, y sobre los palacios de tierra de Egipto, y decid: Reuníos sobre los montes de Samaria, y ved muchas opresiones en medio de ella, y violencias en medio de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 3, 10, 'Y no saben hacer lo recto, dice Jehová, atesorando rapiñas y despojos en sus palacios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 3, 11, 'Por tanto, el Señor Jehová ha dicho así: Un enemigo habrá aún por todos lados de la tierra, y derribará de ti tu fortaleza, y tus palacios serán saqueados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 3, 12, 'Así ha dicho Jehová: De la manera que el pastor libra de la boca del león dos piernas, ó la punta de una oreja, así escaparán los hijos de Israel que moran en Samaria en el rincón de la cama, y al canto del lecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 3, 13, 'Oid y protestad en la casa de Jacob, ha dicho Jehová Dios de los ejércitos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 3, 14, 'Que el día que visitaré las rebeliones de Israel sobre él, visitaré también sobre los altares de Beth-el; y serán cortados los cuernos del altar, y caerán á tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 3, 15, 'Y heriré la casa del invierno con la casa del verano, y las casas de marfil perecerán; y muchas casas serán arruinadas, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 4, 1, 'OID esta palabra, vacas de Basán, que estáis en el monte de Samaria, que oprimís los pobres, que quebrantáis los menesterosos, que decis á sus señores: Traed, y beberemos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 4, 2, 'El Señor Jehová juró por su santidad: He aquí, vienen días sobre vosotros en que os llevará en anzuelos, y á vuestros descendientes en barquillos de pescador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 4, 3, 'Y saldrán por los portillos la una en pos de la otra, y seréis echadas del palacio, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 4, 4, 'Id á Beth-el, y prevaricad; en Gilgal aumentad la rebelión, y traed de mañana vuestros sacrificios, vuestros diezmos cada tres años;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 4, 5, 'Y ofreced sacrificio de alabanza con leudo, y pregonad, publicad voluntarias ofrendas; pues que así lo queréis, hijos de Israel, dice el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 4, 6, 'Yo también os dí limpieza de dientes en todas vuestras ciudades, y falta de pan en todos vuestros pueblos: mas no os tornasteis á mí, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 4, 7, 'Y también yo os detuve la lluvia tres meses antes de la siega: é hice llover sobre una ciudad, y sobre otra ciudad no hice llover: sobre una parte llovió; la parte sobre la cual no llovió, secóse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 4, 8, 'Y venían dos ó tres ciudades á una ciudad para beber agua, y no se hartaban: con todo no os tornásteis á mí, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 4, 9, 'Os herí con viento solano y oruga; vuestros muchos huertos y vuestras viñas, y vuestros higuerales y vuestros olivares comió la langosta: pero nunca os tornasteis á mí, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 4, 10, 'Envié entre vosotros mortandad al modo que en Egipto: maté á cuchillo vuestros mancebos, con cautiverio de vuestros caballos; é hice subir el hedor de vuestros reales hasta vuestras narices: empero no os tornasteis á mí, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 4, 11, 'Trastornéos, como cuando Dios trastornó á Sodoma y á Gomorra, y fuisteis como tizón escapado del fuego: mas no os tornasteis á mí, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 4, 12, 'Por tanto, de esta manera haré á ti, oh Israel: y porque te he de hacer esto, aparéjate para venir al encuentro á tu Dios, oh Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 4, 13, 'Porque he aquí, el que forma los montes, y cría el viento, y denuncia al hombre su pensamiento; el que hace á las tinieblas mañana, y pasa sobre las alturas de la tierra; Jehová, Dios de los ejércitos, es su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 1, 'OID esta palabra, porque yo levanto endecha sobre vosotros, casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 2, 'Cayó la virgen de Israel, no más podrá levantarse; dejada fué sobre su tierra, no hay quien la levante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 3, 'Porque así ha dicho el Señor Jehová: La ciudad que sacaba mil, quedará con ciento; y la que sacaba ciento, quedará con diez, en la casa de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 4, 'Empero así dice Jehová á la casa de Israel: Buscadme, y viviréis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 5, 'Y no busquéis á Beth-el ni entreis en Gilgal, ni paséis á Beer-seba: porque Gilgal será llevada en cautiverio, y Beth-el será deshecha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 6, 'Buscad á Jehová, y vivid; no sea que hienda, como fuego, á la casa de José, y la consuma, sin haber en Beth-el quien lo apague.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 7, 'Los que convierten en ajenjo el juicio, y dejan en tierra la justicia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 8, 'Miren al que hace el Arcturo y el Orión, y las tinieblas vuelve en mañana, y hace oscurecer el día en noche; el que llama á las aguas de la mar, y las derrama sobre la haz de la tierra: Jehová es su nombre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 9, 'Que da esfuerzo al despojador sobre el fuerte, y que el despojador venga contra la fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 10, 'Ellos aborrecieron en la puerta al reprensor, y al que hablaba lo recto abominaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 11, 'Por tanto, pues que vejáis al pobre y recibís de él carga de trigo; edificasteis casas de sillares, mas no las habitaréis; plantasteis hermosas viñas, mas no beberéis el vino de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 12, 'Porque sabido he vuestras muchas rebeliones, y vuestros grandes pecados: que afligen al justo, y reciben cohecho, y á los pobres en la puerta hacen perder su causa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 13, 'Por tanto, el prudente en tal tiempo calla, porque el tiempo es malo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 14, 'Buscad lo bueno, y no lo malo, para que viváis; porque así Jehová Dios de los ejércitos será con vosotros, como decís.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 15, 'Aborreced el mal, y amad el bien, y poned juicio en la puerta: quizá Jehová, Dios de los ejércitos, tendrá piedad del remanente de José.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 16, 'Por tanto, así ha dicho Jehová Dios de los ejércitos, el Señor: En todas las plazas habrá llanto, y en todas las calles dirán, ¡Ay! ¡ay! y al labrador llamarán á lloro, y á endecha á los que endechar supieren.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 17, 'Y en todas las viñas habrá llanto; porque pasaré por medio de ti, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 18, '¡Ay de los que desean el día de Jehová! ¿para qué queréis este día de Jehová? Será de tinieblas, y no luz:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 19, 'Como el que huye de delante del león, y se topa con el oso; ó si entrare en casa y arrimare su mano á la pared, y le muerda la culebra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 20, '¿No será el día de Jehová tinieblas, y no luz; oscuridad, que no tiene resplandor?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 21, 'Aborrecí, abominé vuestras solemnidades, y no me darán buen olor vuestras asambleas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 22, 'Y si me ofreciereis holocaustos y vuestros presentes, no los recibiré; ni miraré á los pacíficos de vuestros engordados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 23, 'Quita de mí la multitud de tus cantares, que no escucharé las salmodias de tus instrumentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 24, 'Antes corra el juicio como las aguas, y la justicia como impetuoso arroyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 25, '¿Habéisme ofrecido sacrificios y presentes en el desierto en cuarenta años, casa de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 26, 'Mas llevabais el tabernáculo de vuestro Moloch y Chiún, ídolos vuestros, la estrella de vuestros dioses que os hicisteis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 5, 27, 'Hareos pues trasportar más allá de Damasco, ha dicho Jehová, cuyo nombre es Dios de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 6, 1, '¡AY de los reposados en Sión, y de los confiados en el monte de Samaria, nombrados principales entre las mismas naciones, las cuales vendrán sobre ellos, oh casa de Israel!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 6, 2, 'Pasad á Calne, y mirad; y de allí id á la gran Hamath; descended luego á Gath de los Palestinos: ved si son aquellos reinos mejores que estos reinos, si su término es mayor que vuestro término.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 6, 3, 'Vosotros que dilatáis el día malo, y acercáis la silla de iniquidad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 6, 4, 'Duermen en camas de marfil, y se extienden sobre sus lechos; y comen los corderos del rebaño, y los becerros de en medio del engordadero;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 6, 5, 'Gorjean al son de la flauta, é inventan instrumentos músicos, como David;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 6, 6, 'Beben vino en tazones, y se ungen con los ungüentos más preciosos; y no se afligen por el quebrantamiento de José.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 6, 7, 'Por tanto, ahora pasarán en el principio de los que á cautividad pasaren, y se acercará el clamor de los extendidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 6, 8, 'El Señor Jehová juró por su alma, Jehová Dios de los ejércitos ha dicho: Tengo en abominación la grandeza de Jacob, y aborrezco sus palacios: y la ciudad y su plenitud entregaré al enemigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 6, 9, 'Y acontecerá que si diez hombres quedaren en una casa, morirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 6, 10, 'Y su tió tomará á cada uno, y quemarále para sacar los huesos de casa; y dirá al que estará en los rincones de la casa: ¿Hay aún alguno contigo? Y dirá: No. Y dirá aquél: Calla que no podemos hacer mención del nombre de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 6, 11, 'Porque he aquí, Jehová mandará, y herirá con hendiduras la casa mayor, y la casa menor con aberturas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 6, 12, '¿Correrán los caballos por las peñas? ¿ararán en ellas con vacas? ¿por qué habéis vosotros tornado el juicio en veneno, y el fruto de justicia en ajeno?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 6, 13, 'Vosotros que os alegráis en nada, que decís: ¿No nos hemos adquirido potencia con nuestra fortaleza?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 6, 14, 'Pues he aquí, levantaré yo sobre vosotros, oh casa de Israel, dice Jehová Dios de los ejércitos, gente que os oprimirá desde la entrada de Hamath hasta el arroyo del desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 1, 'ASI me ha mostrado el Señor Jehová: y he aquí, él criaba langostas al principio que comenzaba á crecer el heno tardío; y he aquí, era el heno tardío después de las siegas del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 2, 'Y acaeció que como acabó de comer la hierba de la tierra, yo dije: Señor Jehová, perdona ahora; ¿quién levantará á Jacob? porque es pequeño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 3, 'Arrepintióse Jehová de esto: No será, dijo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 4, 'El Señor Jehová me mostró así: y he aquí, llamaba para juzgar por fuego el Señor Jehová; y consumió un gran abismo, y consumió una parte de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 5, 'Y dije: Señor Jehová, cesa ahora; ¿quién levantará á Jacob? porque es pequeño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 6, 'Arrepintióse Jehová de esto: No será esto tampoco, dijo el Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 7, 'Enseñóme así: he aquí, el Señor estaba sobre un muro hecho á plomo, y en su mano una plomada de albañil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 8, 'Jehová entonces me dijo: ¿Qué ves, Amós? Y dije: Una plomada de albañil. Y el Señor dijo: He aquí, Yo pongo plomada de albañil en medio de mi pueblo Israel: No le pasaré más:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 9, 'Y los altares de Isaac serán destruidos, y los santuarios de Israel serán asolados; y levantaréme con espada sobre la casa de Jeroboam.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 10, 'Entonces Amasías sacerdote de Beth-el envió á decir á Jeroboam, rey de Israel: Amós se ha conjurado contra ti en medio de la casa de Israel: la tierra no puede sufrir todas sus palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 11, 'Porque así ha dicho Amós: Jeroboam morirá á cuchillo, é Israel pasará de su tierra en cautiverio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 12, 'Y Amasías dijo á Amós: Vidente, vete, y huye á tierra de Judá, y come allá tu pan, y profetiza allí:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 13, 'Y no profetices más en Beth-el, porque es santuario del rey, y cabecera del reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 14, 'Entonces respondió Amós, y dijo á Amasías: No soy profeta, ni soy hijo de profeta, sino que soy boyero, y cogedor de cabrahigos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 15, 'Y Jehová me tomó de tras el ganado, y díjome Jehová: Ve, y profetiza á mi pueblo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 16, 'Ahora pues, oye palabra de Jehová. Tú dices: No profetices contra Israel, ni hables contra la casa de Isaac:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 7, 17, 'Por tanto, así ha dicho Jehová: Tu mujer fornicará en la ciudad, y tus hijos y tus hijas caerán á cuchillo, y tu tierra será partida por suertes; y tú morirás en tierra inmunda, é Israel será traspasado de su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 8, 1, 'ASI me ha mostrado Jehová: y he aquí un canastillo de fruta de verano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 8, 2, 'Y dijo: ¿Qué ves, Amós? Y dije: Un canastillo de fruta de verano. Y díjome Jehová: Venido ha el fin sobre mi pueblo Israel; no le pasaré más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 8, 3, 'Y los cantores del templo aullarán en aquel día, dice el Señor Jehová; muchos serán los cuerpos muertos; en todo lugar echados serán en silencio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 8, 4, 'Oid esto, los que tragáis á los menesterosos, y arruináis los pobres de la tierra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 8, 5, 'Diciendo: ¿Cuándo pasará el mes, y venderemos el trigo; y la semana, y abriremos los alfolíes del pan, y achicaremos la medida, y engrandeceremos el precio, y falsearemos el peso engañoso;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 8, 6, 'Para comprar los pobres por dinero, y los necesitados por un par de zapatos, y venderemos las aechaduras del trigo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 8, 7, 'Jehová juró por la gloria de Jacob: No me olvidaré para siempre de todas sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 8, 8, '¿No se ha de estremecer la tierra sobre esto? ¿Y todo habitador de ella no llorará? y subirá toda como un río, y será arrojada, y hundiráse como el río de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 8, 9, 'Y acaecerá en aquel día, dice el Señor Jehová, que haré se ponga el sol al mediodía, y la tierra cubriré de tinieblas en el día claro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 8, 10, 'Y tornaré vuestras fiestas en lloro, y todos vuestros cantares en endechas; y haré poner saco sobre todos lomos, y peladura sobre toda cabeza; y tornaréla como en llanto de unigénito, y su postrimería como día amargo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 8, 11, 'He aquí vienen días, dice el Señor Jehová, en los cuales enviaré hambre á la tierra, no hambre de pan, ni sed de agua, sino de oir palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 8, 12, 'E irán errantes de mar á mar: desde el norte hasta el oriente discurrirán buscando palabra de Jehová, y no la hallarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 8, 13, 'En aquel tiempo las doncellas hermosas y los mancebos desmayarán de sed.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 8, 14, 'Los que juran por el pecado de Samaria, y dicen, Vive tu Dios de Dan: y, Vive el camino de Beer-seba: caerán, y nunca más se levantarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 9, 1, 'VI al Señor que estaba sobre el altar, y dijo: Hiere el umbral, y estremézcanse las puertas: y córtales en piezas la cabeza de todos; y el postrero de ellos mataré á cuchillo: no habrá de ellos quien se fugue, ni quien escape.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 9, 2, 'Aunque cavasen hasta el infierno, de allá los tomará mi mano; y si subieren hasta el cielo, de allá los haré descender.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 9, 3, 'Y si se escondieren en la cumbre del Carmelo, allí los buscaré y los tomaré; y aunque se escondieren de delante de mis ojos en el profundo de la mar, allí mandaré á la culebra, y morderálos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 9, 4, 'Y si fueren en cautiverio, delante de sus enemigos, allí mandaré al cuchillo, y los matará; y pondré sobre ellos mis ojos para mal, y no para bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 9, 5, 'El Señor Jehová de los ejércitos es el que toca la tierra, y se derretirá, y llorarán todos los que en ella moran: y subirá toda como un río, y hundiráse luego como el río de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 9, 6, 'El edificó en el cielo sus gradas, y ha establecido su expansión sobre la tierra: él llama las aguas de la mar, y sobre la haz de la tierra las derrama: Jehová es su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 9, 7, 'Hijos de Israel, ¿no me sois vosotros, dice Jehová, como hijos de Etiopes? ¿no hice yo subir á Israel de la tierra de Egipto, y á los Palestinos de Caphtor, y de Chîr á los Arameos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 9, 8, 'He aquí los ojos del Señor Jehová están contra el reino pecador, y yo lo asolaré de la haz de la tierra: mas no destruiré del todo la casa de Jacob, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 9, 9, 'Porque he aquí yo mandaré, y haré que la casa de Israel sea zarandeada entre todas las gentes, como se zarandea el grano en un harnero, y no cae un granito en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 9, 10, 'A cuchillo morirán todos los pecadores de mi pueblo, que dicen: No se acercará, ni nos alcanzará el mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 9, 11, 'En aquel día yo levantaré el tabernáculo de David, caído, y cerraré sus portillos, y levantaré sus ruinas, y edificarélo como en el tiempo pasado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 9, 12, 'Para que aquellos sobre los cuales es llamado mi nombre, posean el resto de Idumea, y á todas las naciones, dice Jehová que hace esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 9, 13, 'He aquí vienen días, dice Jehová en que el que ara alcanzará al segador, y el pisador de las uvas al que lleva la simiente; y los montes destilarán mosto, y todos los collados se derretirán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 9, 14, 'Y tornaré el cautiverio de mi pueblo Israel, y edificarán ellos las ciudades asoladas, y las habitarán; y plantarán viñas, y beberán el vino de ellas; y harán huertos, y comerán el fruto de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('AMO', 'Amós', 9, 15, 'Pues los plantaré sobre su tierra, y nunca más serán arrancados de su tierra que yo les dí, ha dicho Jehová Dios tuyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 1, 'VISION de Abdías. El Señor Jehová ha dicho así cuanto á Edom: Oído hemos el pregón de Jehová, y mensajero es enviado á las gentes. Levantaos, y levantémonos contra ella en batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 2, 'He aquí, pequeño te he hecho entre las gentes; abatido eres tú en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 3, 'La soberbia de tu corazón te ha engañado, tú que moras en las hendiduras de las peñas, en tu altísima morada; que dices en tu corazón: ¿Quién me derribará á tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 4, 'Si te encaramares como águila, y si entre las estrellas pusieres tu nido, de ahí te derribaré, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 5, 'Si ladrones vinieran á ti, ó robadores de noche (¡cómo has sido destruído!) ¿no hurtaran lo que les bastase? Pues si entraran á ti vendimiadores, aun dejaran algún rebusco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 6, '¡Cómo fueron escudriñadas las cosas de Esaú! sus cosas escondidas fueron buscadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 7, 'Hasta el término te hicieron llegar todos tus aliados; te han engañado tus pacíficos, prevalecieron contra ti; los que comían tu pan, pusieron el lazo debajo de ti: no hay en él entendimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 8, '¿No haré que perezcan en aquel día, dice Jehová, los sabios de Edom, y la prudencia del monte de Esaú?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 9, 'Y tus valientes, oh Temán, serán quebrantados; porque todo hombre será talado del monte de Esaú por el estrago.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 10, 'Por la injuria de tu hermano Jacob te cubrirá vergüenza, y serás talado para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 11, 'El día que estando tú delante, llevaban extraños cautivo su ejército, y los extraños entraban por sus puertas, y echaban suertes sobre Jerusalem, tú también eras como uno de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 12, 'Pues no debiste tú estar mirando en el día de tu hermano, el día en que fué extrañado: no te habías de haber alegrado de los hijos de Judá en el día que se perdieron, ni habías de ensanchar tu boca en el día de la angustia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 13, 'No habías de haber entrado por la puerta de mi pueblo en el día de su quebrantamiento; no, no habías tú de haber mirado su mal el día de su quebranto, ni haber echado mano á sus bienes el día de su calamidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 14, 'Tampoco habías de haberte parado en las encrucijadas, para matar los que de ellos escapasen; ni habías tú de haber entregado los que quedaban en el día de angustia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 15, 'Porque cercano está el día de Jehová sobre todas las gentes: como tú hiciste se hará contigo: tu galardón volverá sobre tu cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 16, 'De la manera que vosotros bebisteis en mi santo monte, beberán, todas las gentes de continuo: beberán, y engullirán, y serán como si no hubieran sido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 17, 'Mas en el monte de Sión habrá salvamento, y será santidad, y la casa de Jacob, poseerá sus posesiones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 18, 'Y la casa de Jacob será fuego, y la casa de José será llama, y la casa de Esaú estopa, y los quemarán, y los consumirán; ni aun reliquia quedará en la casa de Esaú, porque Jehová lo habló.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 19, 'Y los del mediodía poseerán el monte de Esaú, y los llanos de los Palestinos; poseerán también los campos de Ephraim, y los campos de Samaria; y Benjamín á Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 20, 'Y los cautivos de aqueste ejército de los hijos de Israel poseerán lo de los Cananeos hasta Sarepta; y los cautivos de Jerusalem, que están en Sepharad, poseerán las ciudades del mediodía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('OBA', 'Abdías', 1, 21, 'Y vendrán salvadores al monte de Sión para juzgar al monte de Esaú; y el reino será de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 1, 'Y FUÉ palabra de Jehová á Jonás, hijo de Amittai, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 2, 'Levántate, y ve á Nínive, ciudad grande, y pregona contra ella; porque su maldad ha subido delante de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 3, 'Y Jonás se levantó para huir de la presencia de Jehová á Tarsis, y descendió á Joppe; y halló un navío que partía para Tarsis; y pagando su pasaje entró en él, para irse con ellos á Tarsis de delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 4, 'Mas Jehová hizo levantar un gran viento en la mar, é hízose una tan gran tempestad en la mar, que pensóse se rompería la nave.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 5, 'Y los marineros tuvieron miedo, y cada uno llamaba á su dios: y echaron á la mar los enseres que había en la nave, para descargarla de ellos. Jonás empero se había bajado á los lados del buque, y se había echado á dormir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 6, 'Y el maestre de la nave se llegó á él, y le dijo: ¿Qué tienes, dormilón? Levántate, y clamá á tu Dios; quizá él tendrá compasión de nosotros, y no pereceremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 7, 'Y dijeron cada uno á su compañero: Venid, y echemos suertes, para saber por quién nos ha venido este mal. Y echaron suertes, y la suerte cayó sobre Jonás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 8, 'Entonces le dijeron ellos: Decláranos ahora por qué nos ha venido este mal. ¿Qué oficio tienes, y de dónde vienes? ¿cuál es tu tierra, y de qué pueblo eres?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 9, 'Y él les respondió: Hebreo soy, y temo á Jehová, Dios de los cielos, que hizo la mar y la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 10, 'Y aquellos hombres temieron sobremanera, y dijéronle: ¿Por qué has hecho esto? Porque ellos entendieron que huía de delante de Jehová, porque se lo había declarado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 11, 'Y dijéronle: ¿Qué te haremos, para que la mar se nos quiete? porque la mar iba á más, y se embravecía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 12, 'El les respondió: Tomadme, y echadme á la mar, y la mar se os quietará: porque yo sé que por mí ha venido esta grande tempestad sobre vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 13, 'Y aquellos hombres trabajaron por tornar la nave á tierra; mas no pudieron, porque la mar iba á más, y se embravecía sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 14, 'Entonces clamaron á Jehová, y dijeron: Rogámoste ahora, Jehová, que no perezcamos nosotros por la vida de aqueste hombre, ni pongas sobre nosotros la sangre inocente: porque tú, Jehová, has hecho como has querido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 15, 'Y tomaron á Jonás, y echáronlo á la mar; y la mar se quietó de su furia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 16, 'Y temieron aquellos hombres á Jehová con gran temor; y ofrecieron sacrificio á Jehová, y prometieron votos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 1, 17, '(2-1) MAS Jehová había prevenido un gran pez que tragase á Jonás: y estuvo Jonás en el vientre del pez tres días y tres noches.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 2, 1, '(2-2) Y oró Jonás desde el vientre del pez á Jehová su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 2, 2, '(2-3) Y dijo: Clamé de mi tribulación á Jehová, Y él me oyó; Del vientre del sepulcro clamé, Y mi voz oiste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 2, 3, '(2-4) Echásteme en el profundo, en medio de los mares, Y rodeóme la corriente; Todas tus ondas y tus olas pasaron sobre mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 2, 4, '(2-5) Y yo dije: Echado soy de delante de tus ojos: Mas aun veré tu santo templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 2, 5, '(2-6) Las aguas me rodearon hasta el alma, Rodeóme el abismo; La ova se enredó á mi cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 2, 6, '(2-7) Descendí á las raíces de los montes; La tierra echó sus cerraduras sobre mí para siempre: Mas tú sacaste mi vida de la sepultura, oh Jehová Dios mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 2, 7, '(2-8) Cuando mi alma desfallecía en mí, acordéme de Jehová; Y mi oración entró hasta ti en tu santo templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 2, 8, '(2-9) Los que guardan las vanidades ilusorias, Su misericordia abandonan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 2, 9, '(2-10) Yo empero con voz de alabanza te sacrificaré; Pagaré lo que prometí. La salvación pertenece á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 2, 10, '(2-11) Y mandó Jehová al pez, y vomitó á Jonás en tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 3, 1, 'Y FUÉ palabra de Jehová segunda vez á Jonás, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 3, 2, 'Levántate, y ve á Nínive, aquella gran ciudad, y publica en ella el pregón que yo te diré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 3, 3, 'Y levantóse Jonás, y fué á Nínive, conforme á la palabra de Jehová. Y era Nínive ciudad sobremanera grande, de tres días de camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 3, 4, 'Y comenzó Jonás á entrar por la ciudad, camino de un día, y pregonaba diciendo: De aquí á cuarenta días Nínive será destruida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 3, 5, 'Y los hombres de Nínive creyeron á Dios, y pregonaron ayuno, y vistiéronse de sacos desde el mayor de ellos hasta el menor de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 3, 6, 'Y llegó el negocio hasta el rey de Nínive, y levantóse de su silla, y echó de sí su vestido, y cubrióse de saco, y se sentó sobre ceniza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 3, 7, 'E hizo pregonar y anunciar en Nínive, por mandado del rey y de sus grandes, diciendo: Hombres y animales, bueyes y ovejas, no gusten cosa alguna, no se les dé alimento, ni beban agua:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 3, 8, 'Y que se cubran de saco los hombres y los animales, y clamen á Dios fuertemente: y conviértase cada uno de su mal camino, de la rapiña que está en sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 3, 9, '¿Quién sabe si se volverá y arrepentirá Dios, y se apartará del furor de su ira, y no pereceremos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 3, 10, 'Y vió Dios lo que hicieron, que se convirtieron de su mal camino: y arrepintióse del mal que había dicho les había de hacer, y no lo hizo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 4, 1, 'PERO Jonás se apesadumbró en extremo, y enojóse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 4, 2, 'Y oró á Jehová, y dijo: Ahora, oh Jehová, ¿no es esto lo que yo decía estando aún en mi tierra? Por eso me precaví huyendo á Tarsis; porque sabía yo que tú eres Dios clemente y piadoso, tardo á enojarte, y de grande misericordia, y que te arrepientes del mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 4, 3, 'Ahora pues, oh Jehová, ruégote que me mates; porque mejor me es la muerte que la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 4, 4, 'Y Jehová le dijo: ¿Haces tú bien en enojarte tanto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 4, 5, 'Y salióse Jonás de la ciudad, y asentó hacia el oriente de la ciudad, é hízose allí una choza, y se sentó debajo de ella á la sombra, hasta ver qué sería de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 4, 6, 'Y preparó Jehová Dios una calabacera, la cual creció sobre Jonás para que hiciese sombra sobre su cabeza, y le defendiese de su mal: y Jonás se alegró grandemente por la calabacera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 4, 7, 'Mas Dios preparó un gusano al venir la mañana del día siguiente, el cual hirió á la calabacera, y secóse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 4, 8, 'Y acaeció que al salir el sol, preparó Dios un recio viento solano; y el sol hirió á Jonás en la cabeza, y desmayábase, y se deseaba la muerte, diciendo: Mejor sería para mí la muerte que mi vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 4, 9, 'Entonces dijo Dios á Jonás: ¿Tanto te enojas por la calabacera? Y él respondió: Mucho me enojo, hasta la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 4, 10, 'Y dijo Jehová: Tuviste tú lástima de la calabacera, en la cual no trabajaste, ni tú la hiciste crecer; que en espacio de una noche nació, y en espacio de otra noche pereció:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('JON', 'Jonás', 4, 11, '¿Y no tendré yo piedad de Nínive, aquella grande ciudad donde hay más de ciento y veinte mil personas que no conocen su mano derecha ni su mano izquierda, y muchos animales?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 1, 1, 'CARGA de Nínive. Libro de la visión de Nahum de Elkosh.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 1, 2, 'Dios celoso y vengador es Jehová; vengador es Jehová, y Señor de ira; Jehová, que se venga de sus adversarios, y que guarda enojo para sus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 1, 3, 'Jehová es tardo para la ira, y grande en poder, y no tendrá al culpado por inocente. Jehová marcha entre la tempestad y turbión, y las nubes son el polvo de sus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 1, 4, 'El amenaza á la mar, y la hace secar, y agosta todos los ríos: Basán fué destruído, y el Carmelo, y la flor del Líbano fué destruída.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 1, 5, 'Los montes tiemblan de él, y los collados se deslíen; y la tierra se abrasa á su presencia, y el mundo, y todos los que en él habitan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 1, 6, '¿Quién permanecerá delante de su ira? ¿y quién quedará en pié en el furor de su enojo? Su ira se derrama como fuego, y por él se hienden las peñas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 1, 7, 'Bueno es Jehová para fortaleza en el día de la angustia; y conoce á los que en él confían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 1, 8, 'Mas con inundación impetuosa hará consumación de su lugar, y tinieblas perseguirán á sus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 1, 9, '¿Qué pensáis contra Jehová? El hará consumación: la tribulación no se levantará dos veces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 1, 10, 'Porque como espinas entretegidas, mientras se embriagarán los borrachos, serán consumidos como las estopas llenas de sequedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 1, 11, 'De ti salió el que pensó mal contra Jehová, un consultor impío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 1, 12, 'Así ha dicho Jehová: Aunque reposo tengan, y sean tantos, así serán talados, y él pasará. Bien que te he afligido, no más te afligiré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 1, 13, 'Porque ahora quebraré su yugo de sobre ti, y romperé tus coyundas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 1, 14, 'Mas acerca de ti mandará Jehová, que nunca más sea sembrado alguno de tu nombre: de la casa de tu dios talaré escultura y estatua de fundición, haréla tu sepulcro; porque fuiste vil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 1, 15, 'He aquí sobre los montes los pies del que trae buenas nuevas, del que pregona la paz. Celebra, oh Judá, tus fiestas, cumple tus votos: porque nunca más pasará por ti el malvado; pereció del todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 2, 1, 'SUBIO destruidor contra ti: guarda la fortaleza, mira el camino, fortifica los lomos, fortalece mucho la fuerza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 2, 2, 'Porque Jehová restituirá la gloria de Jacob como la gloria de Israel; porque vaciadores los vaciaron, y estropearon sus mugrones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 2, 3, 'El escudo de sus valientes será bermejo, los varones de su ejército vestidos de grana: el carro como fuego de hachas; el día que se aparejará, temblarán las hayas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 2, 4, 'Los carros se precipitarán á las plazas, discurrirán por las calles: su aspecto como hachas encendidas; correrán como relámpagos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 2, 5, 'Acordaráse él de sus valientes; andando tropezarán; se apresurarán á su muro, y la cubierta se aparejará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 2, 6, 'Las puertas de los ríos se abrirán, y el palacio será destruido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 2, 7, 'Y la reina fué cautiva; mandarle han que suba, y sus criadas la llevarán gimiendo como palomas, batiendo sus pechos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 2, 8, 'Y fué Nínive de tiempo antiguo como estanque de aguas; mas ellos huyen: Parad, parad; y ninguno mira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 2, 9, 'Saquead plata, saquead oro: no hay fin de las riquezas y suntuosidad de todo ajuar de codicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 2, 10, 'Vacía, y agotada, y despedazada está, y el corazón derretido: batimiento de rodillas, y dolor en todos riñones, y los rostros de todos tomarán negrura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 2, 11, '¿Qué es de la morada de los leones, y de la majada de los cachorros de los leones, donde se recogía el león, y la leona, y los cachorros del león, y no había quien les pusiese miedo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 2, 12, 'El león arrebataba en abundancia para sus cachorros, y ahogaba para sus leonas, y henchía de presa sus cavernas, y de robo sus moradas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 2, 13, 'Heme aquí contra ti, dice Jehová de los ejércitos. Encenderé y reduciré á humo tus carros, y espada devorará tus leoncillos; y raeré de la tierra tu robo, y nunca más se oirá voz de tus embajadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 1, '¡AY de la ciudad de sangres, toda llena de mentira y de rapiña, sin apartarse de ella el pillaje!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 2, 'Sonido de látigo, y estruendo de movimiento de ruedas; y caballo atropellador, y carro saltador;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 3, 'Caballero enhiesto, y resplandor de espada, y resplandor de lanza; y multitud de muertos, y multitud de cadáveres; y de sus cadáveres no habrá fin, y en sus cadáveres tropezarán:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 4, 'A causa de la multitud de las fornicaciones de la ramera de hermosa gala, maestra de brujerías, que vende las gentes con sus fornicaciones, y los pueblos con sus hechizos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 5, 'Heme aquí contra ti, dice Jehová de los ejércitos, y descubriré tus faldas en tu cara, y mostraré á las gentes tu desnudez, y á los reinos tu vergüenza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 6, 'Y echaré sobre ti suciedades, y te afrentaré, y te pondré como estiércol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 7, 'Y será que todos los que te vieren, se apartarán de ti, y dirán: Nínive es asolada: ¿quién se compadecerá de ella? ¿dónde te buscaré consoladores?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 8, '¿Eres tú mejor que No-amón, que estaba asentada entre ríos, cercada de aguas, cuyo baluarte era la mar, y del mar su muralla?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 9, 'Etiopía era su fortaleza, y Egipto sin límite; Put y Libia fueron en tu ayuda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 10, 'También ella fué llevada en cautiverio: también sus chiquitos fueron estrellados en las encrucijadas de todas las calles; y sobre sus varones echaron suertes, y todos sus magnates fueron aprisionados con grillos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 11, 'Tú también serás embriagada, serás encerrada; tú también buscarás fortaleza á causa del enemigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 12, 'Todas tus fortalezas cual higueras con brevas; que si las sacuden, caen en la boca del que las ha de comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 13, 'He aquí, tu pueblo será como mujeres en medio de ti: las puertas de tu tierra se abrirán de par en par á tus enemigos: fuego consumirá tus barras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 14, 'Provéete de agua para el cerco, fortifica tus fortalezas; entra en el lodo, pisa el barro, fortifica el horno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 15, 'Allí te consumirá el fuego, te talará la espada, te devorará como pulgón: multiplícate como langosta, multiplícate como langosta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 16, 'Multiplicaste tus mercaderes más que las estrellas del cielo: el pulgón hizo presa, y voló.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 17, 'Tus príncipes serán como langostas, y tus grandes como langostas de langostas que se sientan en vallados en día de frío: salido el sol se mudan, y no se conoce el lugar donde estuvieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 18, 'Durmieron tus pastores, oh rey de Asiria, reposaron tus valientes: tu pueblo se derramó por los montes, y no hay quien lo junte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('NAM', 'Nahúm', 3, 19, 'No hay cura para tu quebradura; tu herida se encrudeció: todos los que oyeron tu fama, batirán las manos sobre ti, porque ¿sobre quién no pasó continuamente tu malicia?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 1, 'EN el mes octavo, en el año segundo de Darío, fué palabra de Jehová á Zacarías profeta, hijo de Berechîas, hijo de Iddo, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 2, 'Enojóse Jehová con ira contra vuestros padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 3, 'Les dirás pues: Así ha dicho Jehová de los ejércitos: Volveos á mí, dice Jehová de los ejércitos, y yo me volveré á vosotros, ha dicho Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 4, 'No seáis como vuestros padres, á los cuales dieron voces los primeros profetas, diciendo: Así ha dicho Jehová de los ejércitos: Volveos ahora de vuestros malos caminos, y de vuestras malas obras: y no atendieron, ni me escucharon, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 5, 'Vuestros padres, ¿dónde están? y los profetas ¿han de vivir para siempre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 6, 'Empero mis palabras y mis ordenanzas que mandé á mis siervos los profetas, ¿no alcanzaron á vuestros padres? Por eso se volvieron ellos y dijeron: Como Jehová de los ejércitos pensó tratarnos conforme á nuestros caminos, y conforme á nuestras obras, así lo hizo con nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 7, 'A los veinticuatro del mes undécimo, que es el mes de Sebath, en el año segundo de Darío, fué palabra de Jehová á Zacarías profeta, hijo de Berechîas, hijo de Iddo, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 8, 'Vi de noche, y he aquí un varón que cabalgaba sobre un caballo bermejo, el cual estaba entre los mirtos que había en la hondura; y detrás de él había caballos bermejos, overos, y blancos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 9, 'Entonces dije: ¿Qué son éstos, señor mío? Y díjome el ángel que hablaba conmigo: Yo te enseñaré qué son éstos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 10, 'Y aquel varón que estaba entre los mirtos respondió, y dijo: Estos son los que Jehová ha enviado á recorrer la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 11, 'Y ellos hablaron á aquel ángel de Jehová que estaba entre los mirtos, y dijeron: Hemos recorrido la tierra, y he aquí toda la tierra está reposada y quieta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 12, 'Y respondió el ángel de Jehová, y dijo: Oh Jehová de los ejércitos, ¿hasta cuándo no tendrás piedad de Jerusalem, y de las ciudades de Judá, con las cuales has estado airado por espacio de setenta años?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 13, 'Y Jehová respondió buenas palabras, palabras consolatorias á aquel ángel que hablaba conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 14, 'Y díjome el ángel que hablaba conmigo: Clama diciendo: Así ha dicho Jehová de los ejércitos: Celé á Jerusalem y á Sión con gran celo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 15, 'Y con grande enojo estoy airado contra las gentes que están reposadas; porque yo estaba enojado un poco, y ellos ayudaron para el mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 16, 'Por tanto, así ha dicho Jehová: Yo me he tornado á Jerusalem con miseraciones; en ella será edificada mi casa, dice Jehová de los ejércitos, y la plomada será tendida sobre Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 17, 'Clama aún, diciendo: Así dice Jehová de los ejércitos: Aun serán ensanchadas mis ciudades por la abundancia del bien; y aun consolará Jehová á Sión, y escogerá todavía á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 18, 'Después alcé mis ojos, y miré, y he aquí cuatro cuernos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 19, 'Y dije al ángel que hablaba conmigo: ¿Qué son éstos? Y respondióme: Estos son los cuernos que aventaron á Judá, á Israel, y á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 20, 'Mostróme luego Jehová cuatro carpinteros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 1, 21, 'Y yo dije: ¿Qué vienen éstos á hacer? Y respondióme, diciendo: Estos son los cuernos que aventaron á Judá, tanto que ninguno alzó su cabeza; mas éstos han venido para hacerlos temblar, para derribar los cuernos de las gentes, que alzaron el cuerno sobre la tierra de Judá para aventarla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 2, 1, 'ALCÉ después mis ojos, y miré y he aquí un varón que tenía en su mano un cordel de medir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 2, 2, 'Y díjele: ¿A dónde vas? Y él me respondió: A medir á Jerusalem, para ver cuánta es su anchura, y cuánta su longitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 2, 3, 'Y he aquí, salía aquel ángel que hablaba conmigo, y otro ángel le salió al encuentro,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 2, 4, 'Y díjole: Corre, habla á este mozo, diciendo: Sin muros será habitada Jerusalem á causa de la multitud de los hombres, y de las bestias en medio de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 2, 5, 'Yo seré para ella, dice Jehová, muro de fuego en derredor, y seré por gloria en medio de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 2, 6, 'Eh, eh, huid de la tierra del aquilón, dice Jehová, pues por los cuatro vientos de los cielos os esparcí, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 2, 7, 'Oh Sión, la que moras con la hija de Babilonia, escápate.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 2, 8, 'Porque así ha dicho Jehová de los ejércitos: Después de la gloria me enviará él á las gentes que os despojaron: porque el que os toca, toca á la niña de su ojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 2, 9, 'Porque he aquí yo alzo mi mano sobre ellos, y serán despojo á sus siervos, y sabréis que Jehová de los ejércitos me envió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 2, 10, 'Canta y alégrate, hija de Sión: porque he aquí vengo, y moraré en medio de ti, ha dicho Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 2, 11, 'Y uniránse muchas gentes á Jehová en aquel día, y me serán por pueblo, y moraré en medio de ti; y entonces conocerás que Jehová de los ejércitos me ha enviado á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 2, 12, 'Y Jehová poseerá á Judá su heredad en la tierra santa, y escogerá aún á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 2, 13, 'Calle toda carne delante de Jehová, porque él se ha despertado de su santa morada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 3, 1, 'Y MOSTROME á Josué, el gran sacerdote, el cual estaba delante del ángel de Jehová; y Satán estaba á su mano derecha para serle adversario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 3, 2, 'Y dijo Jehová á Satán: Jehová te reprenda, oh Satán; Jehová, que ha escogido á Jerusalem, te reprenda. ¿No es éste tizón arrebatado del incendio?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 3, 3, 'Y Josué estaba vestido de vestimentas viles, y estaba delante del ángel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 3, 4, 'Y habló el ángel, é intimó á los que estaban delante de sí, diciendo: Quitadle esas vestimentas viles. Y á él dijo: Mira que he hecho pasar tu pecado de ti, y te he hecho vestir de ropas de gala.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 3, 5, 'Después dijo: Pongan mitra limpia sobre su cabeza. Y pusieron una mitra limpia sobre su cabeza, y vistiéronle de ropas. Y el ángel de Jehová estaba en pie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 3, 6, 'Y el ángel de Jehová protestó al mismo Josué, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 3, 7, 'Así dice Jehová de los ejércitos: Si anduvieres por mis caminos, y si guardares mi ordenanza, también tú gobernarás mi casa, también tú guardarás mis atrios, y entre estos que aquí están te daré plaza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 3, 8, 'Escucha pues ahora, Josué gran sacerdote, tú, y tus amigos que se sientan delante de ti; porque son varones simbólicos: He aquí, yo traigo á mi siervo, el Pimpollo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 3, 9, 'Porque he aquí aquella piedra que puse delante de Josué; sobre esta única piedra hay siete ojos: he aquí, yo grabaré su escultura, dice Jehová de los ejércitos, y quitaré el pecado de la tierra en un día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 3, 10, 'En aquel día, dice Jehová de los ejércitos, cada uno de vosotros llamará á su compañero debajo de la vid, y debajo de la higuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 4, 1, 'Y VOLVIO el ángel que hablaba conmigo, y despertóme como un hombre que es despertado de su sueño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 4, 2, 'Y díjome: ¿Qué ves? Y respondí: He mirado, y he aquí un candelero todo de oro, con su vaso sobre su cabeza, y sus siete lámparas encima del candelero; y siete canales para las lámparas que están encima de él;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 4, 3, 'Y sobre él dos olivas, la una á la derecha del vaso, y la otra á su izquierda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 4, 4, 'Proseguí, y hablé á aquel ángel que hablaba conmigo, diciendo: ¿Qué es esto, señor mío?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 4, 5, 'Y el ángel que hablaba conmigo respondió, y díjome: ¿No sabes qué es esto? Y dije: No, señor mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 4, 6, 'Entonces respondió y hablóme, diciendo: Esta es palabra de Jehová á Zorobabel, en que se dice: No con ejército, ni con fuerza, sino con mi espíritu, ha dicho Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 4, 7, '¿Quién eres tú, oh gran monte? Delante de Zorobabel serás reducido á llanura: él sacará la primera piedra con aclamaciones de Gracia, gracia á ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 4, 8, 'Y fué palabra de Jehová á mí, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 4, 9, 'Las manos de Zorobabel echarán el fundamento á esta casa, y sus manos la acabarán; y conocerás que Jehová de los ejércitos me envió á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 4, 10, 'Porque los que menospreciaron el día de las pequeñeces se alergrarán, y verán la plomada en la mano de Zorobabel. Aquellas siete son los ojos de Jehová que recorren por toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 4, 11, 'Hablé más, y díjele: ¿Qué significan estas dos olivas á la derecha del candelero, y á su izquieda?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 4, 12, 'Hablé aún de nuevo, y díjele: ¿Qué significan las dos ramas de olivas que por medio de dos tubos de oro vierten de sí aceite como oro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 4, 13, 'Y respondióme, diciendo: ¿No sabes qué es esto? Y dije: Señor mío, no.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 4, 14, 'Y él dijo: Estos dos hijos de aceite son los que están delante del Señor de toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 5, 1, 'Y TORNÉME, y alcé mis ojos, y miré, y he aquí un rollo que volaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 5, 2, 'Y díjome: ¿Qué ves? Y respondí: Veo un rollo que vuela, de veinte codos de largo, y diez codos de ancho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 5, 3, 'Díjome entonces: Esta es la maldición que sale sobre la haz de toda la tierra; porque todo aquel que hurta, (como está de la una parte del rollo) será destruído; y todo aquel que jura, (como está de la otra parte del rollo) será destruído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 5, 4, 'Yo la saqué, dice Jehová de los ejércitos, y vendrá á la casa del ladrón, y á la casa del que jura falsamente en mi nombre; y permanecerá en medio de su casa, y consumirála, con sus enmaderamientos y sus piedras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 5, 5, 'Y salió aquel ángel que hablaba conmigo, y díjome: Alza ahora tus ojos, y mira qué es esto que sale.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 5, 6, 'Y dije: ¿Qué es? Y él dijo: Este es un epha que sale. Además dijo: Este es el ojo de ellos en toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 5, 7, 'Y he aquí, traían un talento de plomo, y una mujer estaba asentada en medio de aquel epha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 5, 8, 'Y él dijo: Esta es la Maldad; y echóla dentro del epha, y echó la masa de plomo en su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 5, 9, 'Alcé luego mis ojos, y miré, y he aquí dos mujeres que salían, y traían viento en sus alas, y tenían alas como de cigüeña, y alzaron el epha entre la tierra y los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 5, 10, 'Y dije al ángel que hablaba conmigo: ¿A dónde llevan el epha?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 5, 11, 'Y él me respondió: Para que le sea edificada casa en tierra de Shinar: y será asentado y puesto allá sobre su asiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 6, 1, 'Y TORNÉME, y alcé mis ojos y miré, y he aquí cuatro carros que salían de entre dos montes; y aquellos montes eran de metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 6, 2, 'En el primer carro había caballos bermejos, y el segundo carro caballos negros,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 6, 3, 'Y en el tercer carro caballos blancos, y en el cuarto carro caballos overos ruciorodados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 6, 4, 'Respondí entonces, y dije al ángel que conmigo hablaba: Señor mío, ¿qué es esto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 6, 5, 'Y el ángel me respondió, y díjome: Estos son los cuatro vientos de los cielos, que salen de donde están delante del Señor de toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 6, 6, 'En el que estaban los caballos negros, salieron hacia la tierra del aquilón; y los blancos salieron tras ellos; y lo overos salieron hacia la tierra del mediodía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 6, 7, 'Y los rucios salieron, y se afanaron por ir á recorrer la tierra. Y dijo: Id, recorred la tierra. Y recorrieron la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 6, 8, 'Luego me llamó, y hablóme deciendo: Mira, los que salieron hacia la tierra del aquilón hicieron reposar mi espíritu en la tierra del aquilón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 6, 9, 'Y fué á mí palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 6, 10, 'Toma de los del cautiverio, de Heldai, y de Tobías, y de Jedaía, los cuales volvieron de Babilonia; y vendrás tú en aquel día, y entrarás en casa de Josías hijo de Sefanías;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 6, 11, 'Tomarás pues plata y oro, y harás coronas, y las pondrás en la cabeza del gran sacerdote Josué, hijo de Josadac;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 6, 12, 'Y le hablarás, diciendo: Así ha hablado Jehová de los ejércitos, diciendo: He aquí el varón cuyo nombre es Pimpollo, el cual germinará de su lugar, y edificará el templo de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 6, 13, 'El edificará el templo de Jehová, y él llevará gloria, y se sentará y dominará en su trono, y será sacerdote en su solio; y consejo de paz será entre ambos á dos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 6, 14, 'Y Helem, y Tobías, y Jedaía, y Hen, hijo de Sefanías, tendrán coronas por memorial en el templo de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 6, 15, 'Y los que están lejos vendrán y edificarán en el templo de Jehová, y conoceréis que Jehová de los ejércitos me ha enviado á vosotros. Y será esto, si oyereis obedientes la voz de Jehová vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 7, 1, 'Y ACONTECIO en el año cuarto del rey Darío, que fué palabra de Jehová á Zacarías á los cuatro del mes noveno, que es Chisleu;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 7, 2, 'Cuando fué enviado á la casa de Dios, Saraser, con Regem-melech y sus hombres, á implorar el favor de Jehová,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 7, 3, 'Y á hablar á los sacerdotes que estaban en la casa de Jehová de los ejércitos, y á los profetas, diciendo: ¿Lloraremos en el mes quinto? ¿haremos abstinencia como hemos hecho ya algunos años?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 7, 4, 'Fué pues á mí palabra de Jehová de los ejércitos, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 7, 5, 'Habla á todo el pueblo del país, y á los sacerdotes, diciendo: Cuando ayunasteis y llorasteis en el quinto y en el séptimo mes estos setenta años, ¿habéis ayunado para mí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 7, 6, 'Y cuando coméis y bebéis, ¿no coméis y bebéis para vosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 7, 7, '¿No son estas las palabras que publicó Jehová por mano de los profetas primeros, cuando Jerusalem estaba habitada y quieta, y sus ciudades en sus alrededores, y el mediodía y la campiña se habitaban?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 7, 8, 'Y fué palabra de Jehová á Zacarías, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 7, 9, 'Así habló Jehová de los ejércitos, diciendo: Juzgad juicio verdadero, y haced misericordia y piedad cada cual con su hermano:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 7, 10, 'No agraviéis á la viuda, ni al huérfano, ni al extranjero, ni al pobre; ni ninguno piense mal en su corazón contra su hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 7, 11, 'Empero no quisieron escuchar, antes dieron hombro rebelado, y agravaron sus oídos para no oir:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 7, 12, 'Y pusieron su corazón como diamante, para no oir la ley ni las palabras que Jehová de los ejércitos enviaba por su espíritu, por mano de los profetas primeros: fué, por tanto, hecho grande castigo por Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 7, 13, 'Y aconteció que como él clamó, y no escucharon, así ellos clamaron, y yo no escuché, dice Jehová de los ejércitos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 7, 14, 'Antes los esparcí con torbellino por todas las gentes que ellos no conocían, y la tierra fué desolada tras de ellos, sin quedar quien fuese ni viniese; pues tornaron en asolamiento el país deseable.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 1, 'Y FUÉ á mí palabra de Jehová de los ejércitos, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 2, 'Así ha dicho Jehová de los ejércitos: Yo he celado á Sión con grande celo, y con grande ira la celé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 3, 'Así dice Jehová: Yo he restituído á Sión, y moraré en medio de Jerusalem: y Jerusalem se llamará Ciudad de Verdad, y el monte de Jehová de los ejércitos, Monte de Santidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 4, 'Así ha dicho Jehová de los ejércitos: Aun han de morar viejos y viejas en las plazas de Jerusalem, y cada cual con bordón en su mano por la multitud de los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 5, 'Y las calles de la ciudad serán llenas de muchachos y muchachas, que jugarán en las calles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 6, 'Así dice Jehová de los ejércitos: Si esto parecerá dificultoso á los ojos del resto de este pueblo en aquellos días, ¿también será dificultoso delante de mis ojos? dice Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 7, 'Asi ha dicho Jehová de los ejércitos: He aquí, yo salvo mi pueblo de la tierra del oriente, y de la tierra donde se pone el sol;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 8, 'Y traerélos, y habitarán en medio de Jerusalem; y me serán por pueblo, y yo seré á ellos por Dios con verdad y con justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 9, 'Asi ha dicho Jehová de los ejércitos: Esfuércense vuestras manos, de vosotros los que oís en estos días estas palabras de la boca de los profetas, desde el día que se echó el cimiento á la casa de Jehová de los ejércitos, para edificar el templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 10, 'Porque antes de estos días no ha habido paga de hombre, ni paga de bestia, ni hubo paz alguna para entrante ni para saliente, á causa del enemigo: y yo dejé todos los hombres, cada cual contra su compañero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 11, 'Mas ahora no lo haré con el resto de este pueblo como en aquellos días pasados, dice Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 12, 'Porque habrá simiente de paz; la vid dará su fruto, y dará su producto la tierra, y los cielos darán su rocío; y haré que el resto de este pueblo posea todo esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 13, 'Y será que como fuisteis maldición entre las gentes, oh casa de Judá y casa de Israel, así os salvaré, y seréis bendición. No temáis, mas esfuércense vuestras manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 14, 'Porque así ha dicho Jehová de los ejércitos: Como pensé haceros mal cuando vuestros padres me provocaron á ira, dice Jehová de los ejércitos, y no me arrepentí;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 15, 'Así tornando he pensado de hacer bien á Jerusalem y á la casa de Judá en estos días: no temáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 16, 'Estas son las cosas que habéis de hacer: Hablad verdad cada cual con su prójimo; juzgad en vuestras puertas verdad y juicio de paz:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 17, 'Y ninguno de vosotros piense mal en su corazón contra su prójimo, ni améis juramento falso: porque todas estas son cosas que aborrezco, dice Jehová');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 18, 'Y fué á mí palabra de Jehová de los ejércitos, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 19, 'Así ha dicho Jehová de los ejércitos: El ayuno del cuarto mes, y el ayuno del quinto, y el ayuno del séptimo, y el ayuno del décimo, se tornarán á la casa de Judá en gozo y alegría, y en festivas solemnidades. Amad pues verdad y paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 20, 'Así ha dicho Jehová de los ejércitos: Aun vendrán pueblos, y moradores de muchas ciudades;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 21, 'Y vendrán los moradores de la una á la otra, y dirán: Vamos á implorar el favor de Jehová, y á buscar á Jehová de los ejércitos. Yo también iré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 22, 'Y vendrán muchos pueblos y fuertes naciones á buscar á Jehová de los ejércitos en Jerusalem, y á implorar el favor de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 8, 23, 'Así ha dicho Jehová de los ejércitos: En aquellos días acontecerá que diez hombres de todas las lenguas de las gentes, trabarán de la falda de un Judío, diciendo: Iremos con vosotros, porque hemos oído que Dios está con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 1, 'CARGA de la palabra de Jehová contra tierra de Hadrach, y de Damasco su reposo: porque á Jehová están vueltos los ojos de los hombres, y de todas las tribus de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 2, 'Y también Hamath tendrá término en ella; Tiro y Sidón, aunque muy sabia sea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 3, 'Bien que Tiro se edificó fortaleza, y amontonó plata como polvo, y oro como lodo de las calles,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 4, 'He aquí, el Señor la empobrecerá, y herirá en la mar su fortaleza, y ella será consumida de fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 5, 'Ascalón verá, y temerá; Gaza también, y se dolerá en gran manera: asimismo Ecrón, porque su esperanza será confundida; y de Gaza perecerá el rey, y Ascalón no será habitada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 6, 'Y habitará en Asdod un extranjero, y yo talaré la soberbia de los Palestinos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 7, 'Y quitaré sus sangres de su boca, y sus abominaciones de sus dientes, y quedarán ellos también para nuestro Dios, y serán como capitanes en Judá, y Ecrón como el Jebuseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 8, 'Y seré real de ejército á mi casa, á causa del que va y del que viene: y no pasará más sobre ellos angustiador; porque ahora miré con mis ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 9, 'Alégrate mucho, hija de Sión; da voces de júbilo, hija de Jerusalem: he aquí, tu rey vendrá á ti, justo y salvador, humilde, y cabalgando sobre un asno, así sobre un pollino hijo de asna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 10, 'Y de Ephraim destruiré los carros, y los caballo de Jerusalem; y los arcos de guerra serán quebrados: y hablará paz á las gentes; y su señorío será de mar á mar, y desde el río hasta los fines de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 11, 'Y tú también por la sangre de tu pacto serás salva; yo he sacado tus presos del aljibe en que no hay agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 12, 'Tornaos á la fortaleza, oh presos de esperanza: hoy también os anuncio que os daré doblado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 13, 'Porque entesado he para mí á Judá como arco, henchí á Ephraim; y despertaré tus hijos, oh Sión, contra tus hijos, oh Grecia, y te pondré como espada de valiente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 14, 'Y Jehová será visto sobre ellos, y su dardo saldrá como relámpago: y el Señor Jehová tocará trompeta, é irá como torbellinos del austro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 15, 'Jehová de los ejércitos los amparará, y ellos devorarán, y sujetarán á las piedras de la honda, y beberán y harán estrépido como tomados del vino; y se llenarán como cuenco, ó como los lados del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 16, 'Y los salvará en aquel día Jehová su Dios como á rebaño de su pueblo: porque serán engrandecidos en su tierra como piedras de corona.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 9, 17, 'Porque ¡cuánta es su bondad, y cuánta su hermosura! El trigo alegrará á los mancebos, y el vino á las doncellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 10, 1, 'PEDID á Jehová lluvia en la sazón tardía: Jehová hará relámpagos, y os dará lluvia abundante, y hierba en el campo á cada uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 10, 2, 'Porque las imágenes han hablado vanidad, y los adivinos han visto mentira, y han hablado sueños vanos, en vano consuelan: por lo cual se fueron ellos como ovejas, fueron humillados porque no tuvieron pastor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 10, 3, 'Contra los pastores se ha encendido mi enojo, y castigaré los machos de cabrío: mas Jehová de los ejércitos visitará su rebaño, la casa de Judá, y tornarálos como su caballo de honor en la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 10, 4, 'De él saldrá el ángulo, de él la clavija, de él el arco de la guerra, de él también todo apremiador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 10, 5, 'Y serán como valientes, que en la batalla pisan al enemigo en el lodo de las calles; y pelearán, porque Jehová será con ellos; y los que cabalgan en caballos serán avergonzados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 10, 6, 'Porque yo fortificaré la casa de Judá, y guardaré la casa de José; y harélos volver, porque de ellos tendré piedad; y serán como si no los hubiera desechado; porque yo soy Jehová su Dios, que los oiré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 10, 7, 'Y será Ephraim como valiente, y alegraráse su corazón como de vino: sus hijos también verán y se alegrarán; su corazón se gozará en Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 10, 8, 'Yo les silbaré y los juntaré, porque los he redimido; y serán multiplicados como fueron multiplicados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 10, 9, 'Bien que los sembraré entre los pueblos, aun en lejanos países se acordarán de mí; y vivirán con sus hijos, y tornarán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 10, 10, 'Porque yo los tornaré de la tierra de Egipto, y los recogeré de la Asiria; y traerélos á la tierra de Galaad y del Líbano, y no les bastará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 10, 11, 'Y la tribulación pasará por la mar, y en la mar herirá las ondas, y se secarán todas las honduras del río: y la soberbia de Assur será derribada, y se perderá el cetro de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 10, 12, 'Y yo los fortificaré en Jehová, y caminarán en su nombre, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 1, 'OH Líbano, abre tus puertas, y queme fuego tus cedros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 2, 'Aulla, oh haya, porque el cedro cayó, porque los magníficos son talados. Aullad, alcornoques de Basán, porque el fuerte monte es derribado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 3, 'Voz de aullido de pastores, porque su magnificencia es asolada; estruendo de bramidos de cachorros de leones, porque la soberbia del Jordán es destruída.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 4, 'Así ha dicho Jehová mi Dios: Apacienta las ovejas de la matanza;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 5, 'A las cuales mataban sus compradores, y no se tenían por culpables; y el que las vendía, decía: Bendito sea Jehová, que he enriquecido; ni sus pastores tenían piedad de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 6, 'Por tanto, no más tendré piedad de los moradores de la tierra, dice Jehová: porque he aquí, yo entregaré los hombres, cada cual en mano de su compañero, y en mano de su rey; y quebrantarán la tierra, y yo no libraré de sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 7, 'Apacenté pues las ovejas de la matanza, es á saber, los pobres del rebaño. Y me tomé dos cayados; al uno puse por nombre Suavidad, y al otro Ataduras; y apacenté las ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 8, 'E hice matar tres pastores en un mes, y mi alma se angustió por ellos, y también el alma de ellos me aborreció á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 9, 'Y dije: No os apacentaré; la que muriere, muera; y la que se perdiere, se pierda; y las que quedaren, que cada una coma la carne de su compañera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 10, 'Tomé luego mi cayado Suavidad, y quebrélo, para deshacer mi pacto que concerté con todos los pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 11, 'Y fué deshecho en ese día, y así conocieron los pobres del rebaño que miran á mí, que era palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 12, 'Y díjeles: Si os parece bien, dadme mi salario; y si no, dejadlo. Y pesaron para mi salario treinta piezas de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 13, 'Y díjome Jehová: Echalo al tesorero, hermoso precio con que me han apreciado. Y tomé las treinta piezas de plata, y echélas en la casa de Jehová al tesorero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 14, 'Quebré luego el otro mi cayado Ataduras, para romper la hermandad entre Judá é Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 15, 'Y díjome Jehová: Toma aún el hato de un pastor insensato;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 16, '(11-15) porque he aquí, yo levanto pastor en la tierra, que no visitará las perdidas, no buscará la pequeña, no curará la perniquebrada, ni llevará la cansada á cuestas; sino que se comerá la carne de la gruesa, y romperá sus uñas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 11, 17, '(11-16) Mal haya el pastor de nada, que deja el ganado. Espada sobre su brazo, y sobre su ojo derecho: del todo se secará su brazo, y enteramente será su ojo derecho oscurecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 12, 1, 'CARGA de la palabra de Jehová acerca de Israel. Jehová, que extiende los cielos, y funda la tierra, y forma el espíritu del hombre dentro de él, ha dicho:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 12, 2, 'He aquí, yo pongo á Jerusalem por vaso de temblor á todos los pueblos de alrededor cuando estén en el sitio contra Judá y contra Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 12, 3, 'Y será en aquel día, que yo pondré á Jerusalem por piedra pesada á todos los pueblos: todos los que se la cargaren, serán despedazados, bien que todas las gentes de la tierra se juntarán contra ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 12, 4, 'En aquel día, dice Jehová, heriré con aturdimiento á todo caballo, y con locura al que en él sube; mas sobre la casa de Judá abriré mis ojos, y á todo caballo de los pueblos heriré con ceguera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 12, 5, 'Y los capitanes de Judá dirán en su corazón: Mi fuerza son los moradores de Jerusalem en Jehová de los ejércitos su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 12, 6, 'En aquel día pondré los capitanes de Judá como un brasero de fuego en leña, y como una hacha de fuego en gavillas; y consumirán á diestra y á siniestra todos los pueblos alrededor: y Jerusalem será otra vez habitada en su lugar, en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 12, 7, 'Y librará Jehová las tiendas de Judá primero, porque la gloria de la casa de David y del morador de Jerusalem no se engrandezca sobre Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 12, 8, 'En aquel día Jehová defenderá al morador de Jerusalem: y el que entre ellos fuere flaco, en aquel tiempo será como David; y la casa de David como ángeles, como el ángel de Jehová delante de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 12, 9, 'Y será que en aquel día yo procuraré quebrantar todas las gentes que vinieren contra Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 12, 10, 'Y derramaré sobre la casa de David, y sobre los moradores de Jerusalem, espíritu de gracia y de oración; y mirarán á mí, á quien traspasaron, y harán llanto sobre él, como llanto sobre unigénito, afligiéndose sobre él como quien se aflige sobre primogénito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 12, 11, 'En aquel día habrá gran llanto en Jerusalem, como el llanto de Adadrimón en el valle de Megiddo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 12, 12, 'Y la tierra lamentará, cada linaje de por sí; el linaje de la casa de David por sí, y sus mujeres por sí; el linaje de la casa de Nathán por sí, y sus mujeres por sí;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 12, 13, 'El linaje de la casa de Leví por sí, y sus mujeres por sí; el linaje de Simei por sí, y sus mujeres por sí;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 12, 14, 'Todos los otros linajes, los linajes por sí, y sus mujeres por sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 13, 1, 'EN aquel tiempo habrá manantial abierto para la casa de David y para los moradores de Jerusalem, para el pecado y la inmundicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 13, 2, 'Y será en aquel día, dice Jehová de los ejércitos, que talaré de la tierra los nombres de las imágenes, y nunca más vendrán en memoria: y también haré talar de la tierra los profetas, y espíritu de inmundicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 13, 3, 'Y será que cuando alguno más profetizare, diránle su padre y su madre que lo engendraron: No vivirás, porque has hablado mentira en el nombre de Jehová: y su padre y su madre que lo engendraron, le alancearán cuando profetizare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 13, 4, 'Y será en aquel tiempo, que todos los profetas se avergonzarán de su visión cuando profetizaren; ni nunca más se vestirán de manto velloso para mentir');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 13, 5, 'Y dirá: No soy profeta; labrador soy de la tierra: porque esto aprendí del hombre desde mi juventud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 13, 6, 'Y le preguntarán: ¿Qué heridas son éstas en tus manos? Y él responderá: Con ellas fuí herido en casa de mis amigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 13, 7, 'Levántate, oh espada, sobre el pastor, y sobre el hombre compañero mío, dice Jehová de los ejércitos. Hiere al pastor, y se derramarán las ovejas: mas tornaré mi mano sobre los chiquitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 13, 8, 'Y acontecerá en toda la tierra, dice Jehová, que las dos partes serán taladas en ella, y se perderán; mas la tercera quedará en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 13, 9, 'Y meteré en el fuego la tercera parte, y los fundiré como se funde la plata, y probarélos como se prueba el oro. El invocará mi nombre, y yo le oiré, y diré: Pueblo mío: y él dirá: Jehová es mi Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 1, 'HE aquí, el día de Jehová viene, y tus despojos serán repartidos en medio de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 2, 'Porque yo reuniré todas las gentes en batalla contra Jerusalem; y la ciudad será tomada, y saqueadas serán las casas, y forzadas las mujeres: y la mitad de la ciudad irá en cautiverio, mas el resto del pueblo no será talado de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 3, 'Después saldrá Jehová, y peleará con aquellas gentes, como peleó el día de la batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 4, 'Y afirmaránse sus pies en aquel día sobre el monte de las Olivas, que está en frente de Jerusalem á la parte de oriente: y el monte de las Olivas, se partirá por medio de sí hacia el oriente y hacia el occidente haciendo un muy grande valle; y la mitad del monte se apartará hacia el norte, y la otra mitad hacia el mediodía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 5, 'Y huiréis al valle de los montes; porque el valle de los montes llegará hasta Hasal; y huiréis de la manera que huisteis por causa del terremoto en los días de Uzzías, rey de Judá: y vendrá Jehová mi Dios, y con él todos los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 6, 'Y acontecerá que en ese día no habrá luz clara, ni oscura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 7, 'Y será un día, el cual es conocido de Jehová, que ni será día ni noche; mas acontecerá que al tiempo de la tarde habrá luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 8, 'Acontecerá también en aquel día, que saldrán de Jerusalem aguas vivas; la mitad de ellas hacia la mar oriental, y la otra mitad hacia la mar occidental, en verano y en invierno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 9, 'Y Jehová será rey sobre toda la tierra. En aquel día Jehová será uno, y uno su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 10, 'Y toda la tierra se tornará como llanura desde Gabaa hasta Rimmón al mediodía de Jerusalem: y ésta será enaltecida, y habitarse ha en su lugar desde la puerta de Benjamín hasta el lugar de la puerta primera, hasta la puerta de los rincones; y desde la torre de Hananeel hasta los lagares del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 11, 'Y morarán en ella, y nunca más será anatema: sino que será Jerusalem habitada confiadamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 12, 'Y esta será la plaga con que herirá Jehová á todos los pueblos que pelearon contra Jerusalem: la carne de ellos se disolverá estando ellos sobre sus pies, y se consumirán sus ojos en sus cuencas, y su lengua se les deshará en su boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 13, 'Y acontecerá en aquel día que habrá en ellos gran quebrantamiento de Jehová; porque trabará cada uno de la mano de su compañero, y su mano echará contra la mano de su compañero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 14, 'Y Judá también peleará en Jerusalem. Y serán reunidas las riquezas de todas las gentes de alrededor: oro, y plata, y ropas de vestir, en grande abundancia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 15, 'Y tal como esto será la plaga de los caballos, de los mulos, de los camellos, de los asnos, y de todas las bestias que estuvieren en aquellos campamentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 16, 'Y todos los que quedaren de las gentes que vinieron contra Jerusalem subirán de año en año á adorar al Rey, Jehová de los ejércitos, y á celebrar la fiesta de las Cabañas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 17, 'Y acontecerá, que los de las familias de la tierra que no subieren á Jerusalem á adorar al Rey, Jehová de los ejércitos, no vendrá sobre ellos lluvia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 18, 'Y si la familia de Egipto no subiere, y no vinere, sobre ellos no habrá lluvia; vendrá la plaga con que Jehová herirá las gentes que no subieren á celebrar la fiesta de las Cabañas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 19, 'Esta será la pena del pecado de Egipto, y del pecado de todas las gentes que no subieran á celebrar la fiesta de las Cabañas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 20, 'En aquel tiempo estará sobre las campanillas de los caballos: SANTIDAD A JEHOVA; y las ollas en la casa de Jehová serán como los tazones delante del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ZEC', 'Zacarías', 14, 21, 'Y será toda olla en Jerusalem y en Judá santidad á Jehová de los ejércitos: y todos los que sacrificaren, vendrán y tomarán de ellas, y cocerán en ellas: y no habrá más Cananeo alguno en la casa de Jehová de los ejércitos en aquel tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 1, 1, 'CARGA de la palabra de Jehová contra Israel, por mano de Malaquías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 1, 2, 'Yo os he amado, dice Jehová: y dijisteis: ¿En qué nos amaste? ¿No era Esaú hermano de Jacob, dice Jehová, y amé á Jacob,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 1, 3, 'Y á Esaú aborrecí, y torné sus montes en asolamiento, y su posesión para los chacales del desierto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 1, 4, 'Cuando Edom dijere: Nos hemos empobrecido, mas tornemos á edificar lo arruinado; así ha dicho Jehová de los ejércitos: Ellos edificarán, y yo destruiré: y les llamarán Provincia de impiedad, y, Pueblo contra quien Jehová se airó para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 1, 5, 'Y vuestros ojos lo verán, y diréis: Sea Jehová engrandecido sobre la provincia de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 1, 6, 'El hijo honra al padre, y el siervo á su señor: si pues soy yo padre, ¿qué es de mi honra? y si soy señor, ¿qué es de mi temor?, dice Jehová de los ejércitos á vosotros, oh sacerdotes, que menospreciáis mi nombre. Y decís: ¿En qué hemos menospreciado tu nombre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 1, 7, 'Que ofrecéis sobre mi altar pan inmundo. Y dijisteis: ¿En qué te hemos amancillado? En que decís: La mesa de Jehová es despreciable.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 1, 8, 'Y cuando ofrecéis el animal ciego para sacrificar, ¿no es malo? asimismo cuando ofrecéis el cojo ó el enfermo, ¿no es malo? Preséntalo pues á tu príncipe: ¿acaso se agradará de ti, ó le serás acepto? dice Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 1, 9, 'Ahora pues, orad á la faz de Dios que tenga piedad de nosotros: esto de vuestra mano vino: ¿le seréis agradables? dice Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 1, 10, '¿Quién también hay de vosotros que cierre las puertas ó alumbre mi altar de balde? Yo no recibo contentamiento en vosotros, dice Jehová de los ejércitos, ni de vuestra mano me será agradable el presente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 1, 11, 'Porque desde donde el sol nace hasta donde se pone, es grande mi nombre entre las gentes; y en todo lugar se ofrece á mi nombre perfume, y presente limpio: porque grande es mi nombre entre las gentes, dice Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 1, 12, 'Y vosotros lo habéis profanado cuando decís: Inmunda es la mesa de Jehová; y cuando hablan que su alimento es despreciable.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 1, 13, 'Habéis además dicho: ¡Oh qué trabajo! y lo desechasteis, dice Jehová de los ejércitos; y trajisteis lo hurtado, ó cojo, ó enfermo, y presentasteis ofrenda. ¿Seráme acepto eso de vuesta mano? dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 1, 14, 'Maldito el engañoso, que tiene macho en su rebaño, y promete, y sacrifica lo dañado á Jehová: porque yo soy Gran Rey, dice Jehová de los ejércitos, y mi nombre es formidable entre las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 1, 'AHORA pues, oh sacerdotes, á vosotros es este mandamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 2, 'Si no oyereis, y si no acordareis dar gloria á mi nombre, ha dicho Jehová de los ejércitos, enviaré maldición sobre vosotros, y maldeciré vuestras bendiciones; y aun las he maldecido, porque no lo ponéis en vuestro corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 3, 'He aquí, yo os daño la sementera, y esparciré el estiércol sobre vuestros rostros, el estiércol de vuestras solemnidades, y con él seréis removidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 4, 'Y sabréis que yo os envié este mandamiento, para que fuese mi pacto con Leví, ha dicho Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 5, 'Mi pacto fué con él de vida y de paz, las cuales cosas yo le dí por el temor; porque me temió, y delante de mi nombre estuvo humillado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 6, 'La Ley de verdad estuvo en su boca, é iniquidad no fué hallada en sus labios: en paz y en justicia anduvo conmigo, y á muchos hizo apartar de la iniquidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 7, 'Porque los labios de los sacerdotes han de guardar la sabiduría, y de su boca buscarán la ley; porque mensajero es de Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 8, 'Mas vosotros os habéis apartado del camino; habéis hecho tropezar á muchos en la ley; habéis corrompido el pacto de Leví, dice Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 9, 'Por tanto, yo también os torné viles y bajos á todo el pueblo, según que vosotros no habéis guardado mis caminos, y en la ley tenéis acepción de personas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 10, '¿No tenemos todos un mismo padre? ¿No nos ha criado un mismo Dios? ¿Por qué menospreciaremos cada uno á su hermano, quebrantando el pacto de nuestros padres?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 11, 'Prevaricó Judá, y en Israel y en Jerusalem ha sido cometida abominación; porque Judá ha profanado la santidad de Jehová que amó, y casádose con hija de dios extraño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 12, 'Jehová talará de las tiendas de Jacob al hombre que hiciere esto, al que vela, y al que responde, y al que ofrece presente á Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 13, 'Y esta otra vez haréis cubrir el altar de Jehová de lágrimas, de llanto, y de clamor; así que no miraré más á presente, para aceptarlo con gusto de vuestra mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 14, 'Mas diréis: ¿Por qué? Porque Jehová ha atestiguado entre ti y la mujer de tu mocedad, contra la cual tú has sido desleal, siendo ella tu compañera, y la mujer de tu pacto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 15, 'Pues qué ¿no hizo él uno solo aunque tenía la abundancia del espíritu? ¿Y por qué uno? Para que procurara una simiente de Dios. Guardaos pues en vuestros espíritus, y contra la mujer de vuestra mocedad no seáis desleales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 16, 'Porque Jehová Dios de Israel ha dicho que él aborrece que sea repudiada; y cubra la iniquidad con su vestido, dijo Jehová de los ejércitos. Guardaos pues en vuestros espíritus, y no seáis desleales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 2, 17, 'Habéis hecho cansar á Jehová con vuestras palabras. Y diréis: ¿En qué le hemos cansado? Cuando decís: Cualquiera que mal hace agrada á Jehová, y en los tales toma contentamiento: de otra manera, ¿dónde está el Dios de juicio?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 1, 'HE aquí, yo envío mi mensajero, el cual preparará el camino delante de mí: y luego vendrá á su templo el Señor á quien vosotros buscáis, y el ángel del pacto, á quien deseáis vosotros. He aquí viene, ha dicho Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 2, '¿Y quién podrá sufrir el tiempo de su venida? ó ¿quién podrá estar cuando él se mostrará? Porque él es como fuego purificador, y como jabón de lavadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 3, 'Y sentarse ha para afinar y limpiar la plata: porque limpiará los hijos de Leví, los afinará como á oro y como á plata; y ofrecerán á Jehová ofrenda con justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 4, 'Y será suave á Jehová la ofrenda de Judá y de Jerusalem, como en los días pasados, y como en los años antiguos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 5, 'Y llegarme he á vosotros á juicio; y seré pronto testigo contra los hechiceros y adúlteros; y contra los que juran mentira, y los que detienen el salario del jornalero, de la viuda, y del huérfano, y los que hacen agravio al extranjero, no teniendo temor de mí, dice Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 6, 'Porque yo Jehová, no me mudo; y así vosotros, hijos de Jacob, no habéis sido consumidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 7, 'Desde los días de vuestros padres os habéis apartado de mis leyes, y no las guardasteis. Tornaos á mí, y yo me tornaré á vosotros, ha dicho Jehová de los ejércitos. Mas dijisteis: ¿En qué hemos de tornar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 8, '¿Robará el hombre á Dios? Pues vosotros me habéis robado. Y dijisteis: ¿En qué te hemos robado? Los diezmos y las primicias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 9, 'Malditos sois con maldición, porque vosotros, la nación toda, me habéis robado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 10, 'Traed todos los diezmos al alfolí, y haya alimento en mi casa; y probadme ahora en esto, dice Jehová de los ejércitos, si no os abriré las ventanas de los cielos, y vaciaré sobre vosotros bendición hasta que sobreabunde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 11, 'Increparé también por vosotros al devorador, y no os corromperá el fruto de la tierra; ni vuestra vid en el campo abortará, dice Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 12, 'Y todas las gentes os dirán bienaventurados; porque seréis tierra deseable, dice Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 13, 'Vuestras palabras han prevalecido contra mí, dice Jehová. Y dijisteis: ¿Qué hemos hablado contra ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 14, 'Habéis dicho: Por demás es servir á Dios; ¿y qué aprovecha que guardemos su ley, y que andemos tristes delante de Jehová de los ejércitos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 15, 'Decimos pues ahora, que bienaventurados los soberbios, y también que los que hacen impiedad son los prosperados: bien que tentaron á Dios, escaparon.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 16, 'Entonces los que temen á Jehová hablaron cada uno á su compañero; y Jehová escuchó y oyó, y fué escrito libro de memoria delante de él para los que temen á Jehová, y para los que piensan en su nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 17, 'Y serán para mí especial tesoro, ha dicho Jehová de los ejércitos, en el día que yo tengo de hacer: y perdonarélos como el hombre que perdona á su hijo que le sirve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 3, 18, 'Entonces os tornaréis, y echaréis de ver la diferencia entre el justo y el malo, entre el que sirve á Dios y el que no le sirve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 4, 1, 'PORQUE he aquí, viene el día ardiente como un horno; y todos los soberbios, y todos los que hacen maldad, serán estopa; y aquel día que vendrá, los abrasará, ha dicho Jehová de los ejércitos, el cual no les dejará ni raíz ni rama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 4, 2, 'Mas á vosotros los que teméis mi nombre, nacerá el Sol de justicia, y en sus alas traerá salud: y saldréis, y saltaréis como becerros de la manada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 4, 3, 'Y hollaréis á los malos, los cuales serán ceniza bajo las plantas de vuestros pies, en el día que yo hago, ha dicho Jehová de los ejércitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 4, 4, 'Acordaos de la ley de Moisés mi siervo, al cual encargué en Horeb ordenanzas y leyes para todo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 4, 5, 'He aquí, yo os envío á Elías el profeta, antes que venga el día de Jehová grande y terrible.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('MAL', 'Malaquías', 4, 6, 'El convertirá el corazón de los padres á los hijos, y el corazón de los hijos á los padres: no sea que yo venga, y con destrucción hiera la tierra.');
